import React, { useState, useEffect, useContext } from 'react';
import { useParams, Link } from 'react-router-dom';
import api from '../services/api';
import { CartContext } from '../context/CartContext';

const BASE_URL = 'http://localhost:5000';

const Product = () => {
  const { id } = useParams();
  const { addToCart } = useContext(CartContext);
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [quantity, setQuantity] = useState(1);
  const [selectedImage, setSelectedImage] = useState(0);
  const [relatedProducts, setRelatedProducts] = useState([]);
  const [added, setAdded] = useState(false);

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const { data } = await api.get(`/products/${id}`);
        setProduct(data);
        setSelectedImage(0);
        setQuantity(1);
        setAdded(false);

        // Fetch related products by category
        const allRes = await api.get('/products');
        const related = allRes.data
          .filter(p => p.category === data.category && p._id !== data._id)
          .slice(0, 4);
        setRelatedProducts(related);
      } catch (error) {
        console.error('Error fetching product', error);
      } finally {
        setLoading(false);
      }
    };

    setLoading(true);
    fetchProduct();
  }, [id]);

  const handleAddToCart = () => {
    addToCart(product, quantity);
    setAdded(true);
    setTimeout(() => setAdded(false), 2000);
  };

  const allImages = product?.images?.length > 0
    ? product.images
    : (product?.imageUrl ? [product.imageUrl] : []);

  if (loading) return <div className="container"><p>Loading...</p></div>;
  if (!product) return <div className="container"><p>Product not found.</p></div>;

  return (
    <div className="container">
      <div className="product-details-container">
        {/* Image Gallery */}
        <div>
          <div
            className="product-details-image"
            style={{
              backgroundImage: allImages[selectedImage] ? `url(${BASE_URL}${allImages[selectedImage]})` : 'none',
              backgroundSize: 'cover',
              backgroundPosition: 'center'
            }}
          ></div>
          {allImages.length > 1 && (
            <div style={{ display: 'flex', gap: '10px', marginTop: '15px' }}>
              {allImages.map((img, i) => (
                <div
                  key={i}
                  onClick={() => setSelectedImage(i)}
                  style={{
                    width: '80px',
                    height: '80px',
                    backgroundImage: `url(${BASE_URL}${img})`,
                    backgroundSize: 'cover',
                    backgroundPosition: 'center',
                    cursor: 'pointer',
                    border: i === selectedImage ? '2px solid var(--color-black)' : '1px solid var(--color-border)',
                    opacity: i === selectedImage ? 1 : 0.6,
                    transition: 'all var(--transition-fast)',
                  }}
                ></div>
              ))}
            </div>
          )}
        </div>

        {/* Product Info */}
        <div className="product-details-info">
          {product.luxuryLabel && (
            <span style={{
              fontSize: '0.7rem', textTransform: 'uppercase', letterSpacing: '2px',
              color: 'gold', marginBottom: '8px', display: 'block'
            }}>
              {product.luxuryLabel}
            </span>
          )}
          <h1 className="product-details-title">{product.name}</h1>
          <div style={{ display: 'flex', alignItems: 'baseline', gap: '12px', marginBottom: '2rem' }}>
            <span className="product-details-price">${product.price}</span>
            {product.oldPrice && (
              <span style={{ textDecoration: 'line-through', color: 'var(--color-gray-dark)', fontSize: '1.1rem' }}>
                ${product.oldPrice}
              </span>
            )}
          </div>
          <p className="product-details-description">{product.description}</p>

          <div style={{ marginBottom: '1rem', fontSize: '0.85rem', color: 'var(--color-gray-dark)' }}>
            <span>Category: </span>
            <span style={{ fontWeight: 500, color: 'var(--color-black)' }}>{product.category}</span>
          </div>

          {product.tags?.length > 0 && (
            <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap', marginBottom: '1.5rem' }}>
              {product.tags.map((tag, i) => (
                <span key={i} style={{
                  padding: '4px 12px', border: '1px solid var(--color-border)',
                  fontSize: '0.75rem', textTransform: 'uppercase', letterSpacing: '0.5px',
                }}>{tag}</span>
              ))}
            </div>
          )}

          {/* Quantity Selector */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px', marginBottom: '1.5rem' }}>
            <span style={{ fontSize: '0.85rem', fontWeight: 500 }}>Quantity</span>
            <div style={{ display: 'flex', border: '1px solid var(--color-border)' }}>
              <button
                onClick={() => setQuantity(Math.max(1, quantity - 1))}
                style={{
                  width: '40px', height: '40px', border: 'none', background: 'var(--color-gray-light)',
                  cursor: 'pointer', fontSize: '1.2rem', display: 'flex', alignItems: 'center', justifyContent: 'center',
                }}
              >−</button>
              <span style={{
                width: '50px', height: '40px', display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontWeight: 500, fontSize: '0.95rem',
              }}>{quantity}</span>
              <button
                onClick={() => setQuantity(quantity + 1)}
                style={{
                  width: '40px', height: '40px', border: 'none', background: 'var(--color-gray-light)',
                  cursor: 'pointer', fontSize: '1.2rem', display: 'flex', alignItems: 'center', justifyContent: 'center',
                }}
              >+</button>
            </div>
          </div>

          <button className="btn" onClick={handleAddToCart} style={{ width: '100%' }}>
            {added ? '✓ Added to Cart' : 'Add to Cart'}
          </button>

          {product.stock <= 5 && product.stock > 0 && (
            <p style={{ marginTop: '10px', fontSize: '0.8rem', color: '#b45309' }}>
              Only {product.stock} left in stock
            </p>
          )}
          {product.stock === 0 && (
            <p style={{ marginTop: '10px', fontSize: '0.8rem', color: '#dc2626' }}>
              Out of stock
            </p>
          )}
        </div>
      </div>

      {/* Related Products */}
      {relatedProducts.length > 0 && (
        <div style={{ marginTop: '80px' }}>
          <h2 className="page-title">You May Also Like</h2>
          <div className="product-grid">
            {relatedProducts.map((rp) => (
              <Link to={`/product/${rp._id}`} key={rp._id} className="product-card">
                <div className="product-image" style={{
                  backgroundImage: rp.imageUrl ? `url(${BASE_URL}${rp.imageUrl})` : 'none',
                  backgroundSize: 'cover', backgroundPosition: 'center'
                }}></div>
                <div className="product-info">
                  <span className="product-name">{rp.name}</span>
                  <span className="product-price">${rp.price}</span>
                </div>
              </Link>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default Product;
